# String utility module with text processing functions

class TextProcessor:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format_with_prefix(self, text: str) -> str:
        return f"{self.prefix}: {text}"

    def repeat_text(self, text: str, count: int) -> str:
        result: str = ""
        i: int = 0
        while i < count:
            result += text
            i += 1
        return result

def reverse_string(s: str) -> str:
    # Simple character-by-character reversal
    chars: list[str] = []
    length: int = len(s)
    i: int = length - 1
    while i >= 0:
        chars.append(s[i])
        i -= 1

    reversed_str: str = ""
    for c in chars:
        reversed_str += c
    return reversed_str

def count_vowels(s: str) -> int:
    vowels: str = "aeiouAEIOU"
    count: int = 0
    for char in s:
        if char in vowels:
            count += 1
    return count

